use hitls_bignum::BigNum;

/// Build a BigNum from big-endian magnitude bytes + sign.
fn bn(bytes: &[u8], neg: bool) -> BigNum {
    let mut b = BigNum::from_bytes_be(bytes);
    if neg && !b.is_zero() {
        b.set_negative(true);
    }
    b
}

/// Signed equality: same magnitude (`to_bytes_be`) AND same sign.
fn eq_signed(got: &BigNum, bytes: &[u8], neg: bool) -> bool {
    let exp = bn(bytes, neg);
    got.to_bytes_be() == exp.to_bytes_be() && got.is_negative() == exp.is_negative()
}

